  1→/**
  2→ * Category content area — renders the header, scope sections, and item list
  3→ * for the currently active config category.
  4→ *
  5→ * Both scopes are always visible: project items first (labeled with repo name),
  6→ * then global items below (dimmed at the card level).
  7→ * When no repoPath is set, only global items are shown at full opacity.
  8→ * When project scope is active but empty, an empty state is shown.
  9→ *
 10→ * CRUD support: category views pass editingItem / addingInScope / pendingDeleteItem
 11→ * along with a renderEditForm render-prop. This component handles placement of
 12→ * the edit form inline, undo strips, and scope section layout.
 13→ */
 14→
 15→import type { ReactNode } from "react";
 16→import { AnimatePresence } from "framer-motion";
 17→import { Plus, FolderGit2, Globe } from "lucide-react";
 18→import { cn } from "@/shared/lib/utils";
 19→import { Button } from "@/components/ui/button";
 20→import {
 21→  DropdownMenu,
 22→  DropdownMenuContent,
 23→  DropdownMenuItem,
 24→  DropdownMenuTrigger,
 25→} from "@/components/ui/dropdown-menu";
 26→import { ConfigItemRow } from "./shared/ConfigItemRow";
 27→import { EmptyState } from "./shared/EmptyState";
 28→import { UndoStrip } from "./shared/UndoStrip";
 29→import type { ConfigDisplayItem, ConfigScope } from "../types";
 30→
 31→interface CategoryContentAreaProps {
 32→  categoryLabel: string;
 33→  globalItems: ConfigDisplayItem[];
 34→  projectItems: ConfigDisplayItem[];
 35→  repoName?: string;
 36→  repoPath?: string;
 37→  isLoading?: boolean;
 38→  onAdd?: (scope: ConfigScope) => void;
 39→  onEdit?: (item: ConfigDisplayItem) => void;
 40→  onDelete?: (item: ConfigDisplayItem) => void;
 41→
 42→  /** The item currently being edited inline (null = nothing editing) */
 43→  editingItem?: ConfigDisplayItem | null;
 44→  /** Which scope section shows the "add new" form (null = not adding) */
 45→  addingInScope?: ConfigScope | null;
 46→  /** Category views provide form content via this render prop. Cancel is owned by the form itself. */
 47→  renderEditForm?: (item: ConfigDisplayItem | null) => ReactNode;
 48→  /** Item awaiting delete (hidden from list, undo strip shown) */
 49→  pendingDeleteItem?: ConfigDisplayItem | null;
 50→  onUndoDelete?: () => void;
 51→  onConfirmDelete?: () => void;
 52→}
 53→
 54→export function CategoryContentArea({
 55→  categoryLabel,
 56→  globalItems,
 57→  projectItems,
 58→  repoName,
 59→  repoPath,
 60→  isLoading,
 61→  onAdd,
 62→  onEdit,
 63→  onDelete,
 64→  editingItem,
 65→  addingInScope,
 66→  renderEditForm,
 67→  pendingDeleteItem,
 68→  onUndoDelete,
 69→  onConfirmDelete,
 70→}: CategoryContentAreaProps) {
 71→  // Both scopes always visible; global dimmed only when project scope is active
 72→  const hasProjectScope = !!repoPath;
 73→  const dimGlobal = hasProjectScope;
 74→
 75→  // Filter out the pending-delete item so it disappears instantly
 76→  const visibleProjectItems =
 77→    pendingDeleteItem?.scope === "project"
 78→      ? projectItems.filter((i) => i.id !== pendingDeleteItem.id)
 79→      : projectItems;
 80→  const visibleGlobalItems =
 81→    pendingDeleteItem?.scope === "global"
 82→      ? globalItems.filter((i) => i.id !== pendingDeleteItem.id)
 83→      : globalItems;
 84→
 85→  const hasGlobalContent = visibleGlobalItems.length > 0 || addingInScope === "global";
 86→  // Project section always visible when scope exists; top-level empty only when nothing at all
 87→  const hasAnyContent = hasProjectScope || hasGlobalContent || pendingDeleteItem != null;
 88→
 89→  const isEditingItem = (item: ConfigDisplayItem) =>
 90→    editingItem != null && editingItem.id === item.id && editingItem.scope === item.scope;
 91→
 92→  return (
 93→    <div className="flex min-w-0 flex-1 flex-col">
 94→      {/* Category header */}
 95→      <div className="border-border/40 flex h-10 shrink-0 items-center justify-between border-b px-4">
