199→/* ------------------------------------------------------------------ */
200→/*  Component                                                           */
201→/* ------------------------------------------------------------------ */
202→
203→export function HooksView({ repoPath, repoName }: HooksViewProps) {
204→  const globalQuery = useAgentConfigList<Record<string, unknown>>("hooks", "global");
205→  const projectQuery = useAgentConfigList<Record<string, unknown>>("hooks", "project", repoPath, {
206→    enabled: !!repoPath,
207→  });
208→
209→  const globalItems = useMemo(
210→    () => hooksToDisplayItems(globalQuery.data, "global"),
