217→  const isLoading = globalQuery.isLoading || (!!repoPath && projectQuery.isLoading);
218→
219→  const saveMutation = useSaveConfigItem("hooks");
220→
221→  const [formEvent, setFormEvent] = useState("");
222→  const [formGroups, setFormGroups] = useState<FormMatcherGroup[]>(createEmptyGroups);
223→
224→  const resetForm = useCallback(() => {
225→    setFormEvent("");
226→    setFormGroups(createEmptyGroups());
227→  }, []);
228→
229→  const populateForm = useCallback((raw: unknown) => {
