287→      const relevantQuery = scope === "project" ? projectQuery : globalQuery;
288→      if (relevantQuery.status !== "success") return;
289→      const currentHooks = relevantQuery.data ?? {};
290→
291→      const parsedHandlers = formGroupsToHandlers(formGroups);
292→      const updatedHooks = { ...currentHooks, [formEvent.trim()]: parsedHandlers };
293→
294→      saveMutation.mutate(
