312→    const { [crud.pendingDelete.id]: _, ...remaining } = currentHooks;
313→    saveMutation.mutate(
314→      { data: { hooks: remaining }, scope, repoPath: scope === "project" ? repoPath : undefined },
315→      { onSettled: () => crud.setPendingDelete(null) }
316→    );
317→  }, [crud, repoPath, saveMutation, globalQuery.data, projectQuery.data]);
318→
319→  /* -- Render edit form -- */
320→
321→  const renderEditForm = useCallback(
