386→              />
387→
388→              <div className="space-y-1.5">
389→                <Label className="text-2xs text-muted-foreground">Commands</Label>
390→                {group.commands.map((cmd, ci) => (
391→                  <div key={ci} className="flex items-center gap-2">
392→                    <Input
393→                      value={cmd.command}
394→                      onChange={(e) => updateCommand(gi, ci, "command", e.target.value)}
