        .with("commands", () => <CommandsView {...categoryProps} />)
        .with("agents", () => <AgentsView {...categoryProps} />)
        .with("mcp", () => <McpView {...categoryProps} />)
        .with("hooks", () => <HooksView {...categoryProps} />)
        .exhaustive()}
    </div>
  );
}

